import{_ as l}from"./plugin-vue_export-helper.21dcd24c.js";import{o as t,c as e,e as i}from"./app.f506c57e.js";const T={},u=i('<h1 id="http\u534F\u8BAE\u72B6\u6001\u7801" tabindex="-1"><a class="header-anchor" href="#http\u534F\u8BAE\u72B6\u6001\u7801" aria-hidden="true">#</a> HTTP\u534F\u8BAE\u72B6\u6001\u7801</h1><table><thead><tr><th style="text-align:center;">\u5206\u7C7B</th><th style="text-align:center;">\u5206\u7C7B\u63CF\u8FF0</th></tr></thead><tbody><tr><td style="text-align:center;">1**</td><td style="text-align:center;">\u4FE1\u606F\uFF0C\u670D\u52A1\u5668\u6536\u5230\u8BF7\u6C42\uFF0C\u9700\u8981\u8BF7\u6C42\u8005\u7EE7\u7EED\u6267\u884C\u64CD\u4F5C</td></tr><tr><td style="text-align:center;">2**</td><td style="text-align:center;">\u6210\u529F\uFF0C\u64CD\u4F5C\u88AB\u6210\u529F\u63A5\u6536\u5E76\u5904\u7406</td></tr><tr><td style="text-align:center;">3**</td><td style="text-align:center;">\u91CD\u5B9A\u5411\uFF0C\u9700\u8981\u8FDB\u4E00\u6B65\u7684\u64CD\u4F5C\u4EE5\u5B8C\u6210\u8BF7\u6C42</td></tr><tr><td style="text-align:center;">4**</td><td style="text-align:center;">\u5BA2\u6237\u7AEF\u9519\u8BEF\uFF0C\u8BF7\u6C42\u5305\u542B\u8BED\u6CD5\u9519\u8BEF\u6216\u65E0\u6CD5\u5B8C\u6210\u8BF7\u6C42</td></tr><tr><td style="text-align:center;">5**</td><td style="text-align:center;">\u670D\u52A1\u5668\u9519\u8BEF\uFF0C\u670D\u52A1\u5668\u5728\u5904\u7406\u8BF7\u6C42\u7684\u8FC7\u7A0B\u4E2D\u53D1\u751F\u4E86\u9519\u8BEF</td></tr></tbody></table><ul><li>100 Continue(\u7EE7\u7EED) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u5BA2\u6237\u7AEF\u5E94\u5F53\u7EE7\u7EED\u53D1\u9001\u8BF7\u6C42.\u8FD9\u4E2A\u4E34\u65F6\u54CD\u5E94\u662F\u7528\u6765\u901A\u77E5\u5BA2\u6237\u7AEF\u5B83\u7684\u90E8\u5206\u8BF7\u6C42\u5DF2\u7ECF\u88AB\u670D\u52A1\u5668\u63A5\u6536,\u4E14\u4ECD\u672A\u88AB\u62D2\u7EDD.\u5BA2\u6237\u7AEF\u5E94\u5F53\u7EE7\u7EED\u53D1\u9001\u8BF7\u6C42\u7684\u5269\u4F59\u90E8\u5206,\u6216\u8005\u5982\u679C\u8BF7\u6C42\u5DF2\u7ECF\u5B8C\u6210,\u5FFD\u7565\u8FD9\u4E2A\u54CD\u5E94.\u670D\u52A1\u5668\u5FC5\u987B\u5728\u8BF7\u6C42\u5B8C\u6210\u540E\u5411\u5BA2\u6237\u7AEF\u53D1\u9001\u4E00\u4E2A\u6700\u7EC8\u54CD\u5E94.</p><ul><li>101 SwitchingProtocol(\u5207\u6362\u534F\u8BAE) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u670D\u52A1\u5668\u5DF2\u7ECF\u7406\u89E3\u4E86\u5BA2\u6237\u7AEF\u7684\u8BF7\u6C42\uFF0C\u5E76\u5C06\u901A\u8FC7Upgrade\u6D88\u606F\u5934\u901A\u77E5\u5BA2\u6237\u7AEF\u91C7\u7528\u4E0D\u540C\u7684\u534F\u8BAE\u6765\u5B8C\u6210\u8FD9\u4E2A\u8BF7\u6C42\u3002\u5728\u53D1\u9001\u5B8C\u8FD9\u4E2A\u54CD\u5E94\u6700\u540E\u7684\u7A7A\u884C\u540E\uFF0C\u670D\u52A1\u5668\u5C06\u4F1A\u5207\u6362\u5230\u5728Upgrade\u6D88\u606F\u5934\u4E2D\u5B9A\u4E49\u7684\u90A3\u4E9B\u534F\u8BAE\u3002:\u53EA\u6709\u5728\u5207\u6362\u65B0\u7684\u534F\u8BAE\u66F4\u6709\u597D\u5904\u7684\u65F6\u5019\u624D\u5E94\u8BE5\u91C7\u53D6\u7C7B\u4F3C\u63AA\u65BD\u3002\u4F8B\u5982\uFF0C\u5207\u6362\u5230\u65B0\u7684HTTP\u7248\u672C\u6BD4\u65E7\u7248\u672C\u66F4\u6709\u4F18\u52BF\uFF0C\u6216\u8005\u5207\u6362\u5230\u4E00\u4E2A\u5B9E\u65F6\u4E14\u540C\u6B65\u7684\u534F\u8BAE\u4EE5\u4F20\u9001\u5229\u7528\u6B64\u7C7B\u7279\u6027\u7684\u8D44\u6E90\u3002</p><ul><li>200 OK(\u6210\u529F) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u8BF7\u6C42\u6210\u529F.\u6210\u529F\u7684\u610F\u4E49\u6839\u636E\u8BF7\u6C42\u6240\u4F7F\u7528\u7684\u65B9\u6CD5\u4E0D\u540C\u800C\u4E0D\u540C.GET:\u8D44\u6E90\u5DF2\u88AB\u63D0\u53D6,\u5E76\u4F5C\u4E3A\u54CD\u5E94\u4F53\u4F20\u56DE\u5BA2\u6237\u7AEF.HEAD:\u5B9E\u4F53\u5934\u5DF2\u4F5C\u4E3A\u54CD\u5E94\u5934\u4F20\u56DE\u5BA2\u6237\u7AEFPOST:\u7ECF\u8FC7\u670D\u52A1\u5668\u5904\u7406\u5BA2\u6237\u7AEF\u4F20\u6765\u7684\u6570\u636E,\u9002\u5408\u7684\u8D44\u6E90\u4F5C\u4E3A\u54CD\u5E94\u4F53\u4F20\u56DE\u5BA2\u6237\u7AEF.TRACE:\u670D\u52A1\u5668\u6536\u5230\u8BF7\u6C42\u6D88\u606F\u4F5C\u4E3A\u54CD\u5E94\u4F53\u4F20\u56DE\u5BA2\u6237\u7AEF.</p><ul><li>201 Created(\u5DF2\u521B\u5EFA) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u8BF7\u6C42\u6210\u529F\uFF0C\u800C\u4E14\u6709\u4E00\u4E2A\u65B0\u7684\u8D44\u6E90\u5DF2\u7ECF\u4F9D\u636E\u8BF7\u6C42\u7684\u9700\u8981\u800C\u5EFA\u7ACB\uFF0C\u901A\u5E38\u8FD9\u662FPUT\u65B9\u6CD5\u5F97\u5230\u7684\u54CD\u5E94\u7801.</p><ul><li>202 Accepted(\u5DF2\u521B\u5EFA) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u670D\u52A1\u5668\u5DF2\u63A5\u53D7\u8BF7\u6C42\uFF0C\u4F46\u5C1A\u672A\u5904\u7406\u3002\u6B63\u5982\u5B83\u53EF\u80FD\u88AB\u62D2\u7EDD\u4E00\u6837\uFF0C\u6700\u7EC8\u8BE5\u8BF7\u6C42\u53EF\u80FD\u4F1A\u4E5F\u53EF\u80FD\u4E0D\u4F1A\u88AB\u6267\u884C\u3002\u5728\u5F02\u6B65\u64CD\u4F5C\u7684\u573A\u5408\u4E0B\uFF0C\u6CA1\u6709\u6BD4\u53D1\u9001\u8FD9\u4E2A\u72B6\u6001\u7801\u66F4\u65B9\u4FBF\u7684\u505A\u6CD5\u4E86\u3002:\u8FD4\u56DE202\u72B6\u6001\u7801\u7684\u54CD\u5E94\u7684\u76EE\u7684\u662F\u5141\u8BB8\u670D\u52A1\u5668\u63A5\u53D7\u5176\u4ED6\u8FC7\u7A0B\u7684\u8BF7\u6C42\uFF08\u4F8B\u5982\u67D0\u4E2A\u6BCF\u5929\u53EA\u6267\u884C\u4E00\u6B21\u7684\u57FA\u4E8E\u6279\u5904\u7406\u7684\u64CD\u4F5C\uFF09\uFF0C\u800C\u4E0D\u5FC5\u8BA9\u5BA2\u6237\u7AEF\u4E00\u76F4\u4FDD\u6301\u4E0E\u670D\u52A1\u5668\u7684\u8FDE\u63A5\u76F4\u5230\u6279\u5904\u7406\u64CD\u4F5C\u5168\u90E8\u5B8C\u6210\u3002\u5728\u63A5\u53D7\u8BF7\u6C42\u5904\u7406\u5E76\u8FD4\u56DE202\u72B6\u6001\u7801\u7684\u54CD\u5E94\u5E94\u5F53\u5728\u8FD4\u56DE\u7684\u5B9E\u4F53\u4E2D\u5305\u542B\u4E00\u4E9B\u6307\u793A\u5904\u7406\u5F53\u524D\u72B6\u6001\u7684\u4FE1\u606F\uFF0C\u4EE5\u53CA\u6307\u5411\u5904\u7406\u72B6\u6001\u76D1\u89C6\u5668\u6216\u72B6\u6001\u9884\u6D4B\u7684\u6307\u9488\uFF0C\u4EE5\u4FBF\u7528\u6237\u80FD\u591F\u4F30\u8BA1\u64CD\u4F5C\u662F\u5426\u5DF2\u7ECF\u5B8C\u6210\u3002</p><ul><li>203 Non-AuthoritativeInformation(\u672A\u6388\u6743\u4FE1\u606F) (HTTP/0.9and1.1)</li></ul><p>\u670D\u52A1\u5668\u5DF2\u6210\u529F\u5904\u7406\u4E86\u8BF7\u6C42,\u4F46\u8FD4\u56DE\u7684\u5B9E\u4F53\u5934\u90E8\u5143\u4FE1\u606F\u4E0D\u662F\u5728\u539F\u59CB\u670D\u52A1\u5668\u4E0A\u6709\u6548\u7684\u786E\u5B9A\u96C6\u5408\uFF0C\u800C\u662F\u6765\u81EA\u672C\u5730\u6216\u8005\u7B2C\u4E09\u65B9\u7684\u62F7\u8D1D,\u5982\u679C\u4E0D\u662F\u4E0A\u8FF0\u60C5\u51B5,\u4F7F\u7528200\u72B6\u6001\u7801\u624D\u662F\u6700\u5408\u9002\u7684.</p><ul><li>204 NoContent(\u65E0\u5185\u5BB9) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u8BE5\u54CD\u5E94\u6CA1\u6709\u54CD\u5E94\u5185\u5BB9,\u53EA\u6709\u54CD\u5E94\u5934,\u54CD\u5E94\u5934\u4E5F\u53EF\u80FD\u662F\u6709\u7528\u7684.\u7528\u6237\u4EE3\u7406\u53EF\u4EE5\u6839\u636E\u65B0\u7684\u54CD\u5E94\u5934\u6765\u66F4\u65B0\u5BF9\u5E94\u8D44\u6E90\u7684\u7F13\u5B58\u4FE1\u606F.</p><ul><li>205 ResetContent(\u91CD\u7F6E\u5185\u5BB9) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u544A\u8BC9\u7528\u6237\u4EE3\u7406\u53BB\u91CD\u7F6E\u53D1\u9001\u8BE5\u8BF7\u6C42\u7684\u7A97\u53E3\u7684\u6587\u6863\u89C6\u56FE.</p><ul><li>206 PartialContent(\u90E8\u5206\u5185\u5BB9) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u5F53\u5BA2\u6237\u7AEF\u901A\u8FC7\u4F7F\u7528range\u5934\u5B57\u6BB5\u8FDB\u884C\u6587\u4EF6\u5206\u6BB5\u4E0B\u8F7D\u65F6\u4F7F\u7528\u8BE5\u72B6\u6001\u7801</p><ul><li>300 MultipleChoice(\u591A\u79CD\u9009\u62E9) (HTTP/1.0andlater)</li></ul><p>\u8BE5\u8BF7\u6C42\u6709\u591A\u79CD\u53EF\u80FD\u7684\u54CD\u5E94,\u7528\u6237\u4EE3\u7406\u6216\u8005\u7528\u6237\u5FC5\u987B\u9009\u62E9\u5B83\u4EEC\u5176\u4E2D\u7684\u4E00\u4E2A.\u670D\u52A1\u5668\u6CA1\u6709\u4EFB\u4F55\u6807\u51C6\u53EF\u4EE5\u9075\u5FAA\u53BB\u4EE3\u66FF\u7528\u6237\u6765\u8FDB\u884C\u9009\u62E9.</p><ul><li>301 MovedPermanently(\u6C38\u4E45\u79FB\u52A8) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u8BE5\u72B6\u6001\u7801\u8868\u793A\u6240\u8BF7\u6C42\u7684URI\u8D44\u6E90\u8DEF\u5F84\u5DF2\u7ECF\u6539\u53D8,\u65B0\u7684URL\u4F1A\u5728\u54CD\u5E94\u7684Location:\u5934\u5B57\u6BB5\u91CC\u627E\u5230.</p><ul><li>302 Found(\u4E34\u65F6\u79FB\u52A8) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u8BE5\u72B6\u6001\u7801\u8868\u793A\u6240\u8BF7\u6C42\u7684URI\u8D44\u6E90\u8DEF\u5F84\u4E34\u65F6\u6539\u53D8,\u5E76\u4E14\u8FD8\u53EF\u80FD\u7EE7\u7EED\u6539\u53D8.\u56E0\u6B64\u5BA2\u6237\u7AEF\u5728\u4EE5\u540E\u8BBF\u95EE\u65F6\u8FD8\u5F97\u7EE7\u7EED\u4F7F\u7528\u8BE5URI.\u65B0\u7684URL\u4F1A\u5728\u54CD\u5E94\u7684Location:\u5934\u5B57\u6BB5\u91CC\u627E\u5230.</p><ul><li>303 SeeOther(\u67E5\u770B\u5176\u4ED6\u4F4D\u7F6E) (HTTP/0.9and1.1)</li></ul><p>\u670D\u52A1\u5668\u53D1\u9001\u8BE5\u54CD\u5E94\u7528\u6765\u5F15\u5BFC\u5BA2\u6237\u7AEF\u4F7F\u7528GET\u65B9\u6CD5\u8BBF\u95EE\u53E6\u5916\u4E00\u4E2AURI.</p><ul><li>304 NotModified(\u672A\u4FEE\u6539) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u544A\u8BC9\u5BA2\u6237\u7AEF,\u6240\u8BF7\u6C42\u7684\u5185\u5BB9\u8DDD\u79BB\u4E0A\u6B21\u8BBF\u95EE\u5E76\u6CA1\u6709\u53D8\u5316.\u5BA2\u6237\u7AEF\u53EF\u4EE5\u76F4\u63A5\u4ECE\u6D4F\u89C8\u5668\u7F13\u5B58\u91CC\u83B7\u53D6\u8BE5\u8D44\u6E90.</p><ul><li>305 UseProxy(\u4F7F\u7528\u4EE3\u7406) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u6240\u8BF7\u6C42\u7684\u8D44\u6E90\u5FC5\u987B\u7EDF\u8FC7\u4EE3\u7406\u624D\u80FD\u8BBF\u95EE\u5230.\u7531\u4E8E\u5B89\u5168\u539F\u56E0,\u8BE5\u72B6\u6001\u7801\u5E76\u672A\u53D7\u5230\u5E7F\u6CDB\u652F\u6301.</p><ul><li>306 unused(\u672A\u4F7F\u7528) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u8FD9\u4E2A\u72B6\u6001\u7801\u5DF2\u7ECF\u4E0D\u518D\u88AB\u4F7F\u7528,\u5F53\u521D\u5B83\u88AB\u7528\u5728HTTP1.1\u89C4\u8303\u7684\u65E7\u7248\u672C\u4E2D.</p><ul><li>307 TemporaryRedirect(\u4E34\u65F6\u91CD\u5B9A\u5411) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u670D\u52A1\u5668\u53D1\u9001\u8BE5\u54CD\u5E94\u7528\u6765\u5F15\u5BFC\u5BA2\u6237\u7AEF\u4F7F\u7528\u76F8\u540C\u7684\u65B9\u6CD5\u8BBF\u95EE\u53E6\u5916\u4E00\u4E2AURI\u6765\u83B7\u53D6\u60F3\u8981\u83B7\u53D6\u7684\u8D44\u6E90.\u65B0\u7684URL\u4F1A\u5728\u54CD\u5E94\u7684Location:\u5934\u5B57\u6BB5\u91CC\u627E\u5230.\u4E0E302\u72B6\u6001\u7801\u6709\u76F8\u540C\u7684\u8BED\u4E49,\u4E14\u524D\u540E\u4E24\u6B21\u8BBF\u95EE\u5FC5\u987B\u4F7F\u7528\u76F8\u540C\u7684\u65B9\u6CD5(GETPOST).</p><ul><li>308 PermanentRedirect(\u6C38\u4E45\u91CD\u5B9A\u5411) (HTTPbis(\u8BD5\u9A8C\u8349\u6848))</li></ul><p>\u6240\u8BF7\u6C42\u7684\u8D44\u6E90\u5C06\u6C38\u4E45\u7684\u4F4D\u4E8E\u53E6\u5916\u4E00\u4E2AURI\u4E0A.\u65B0\u7684URL\u4F1A\u5728\u54CD\u5E94\u7684Location:\u5934\u5B57\u6BB5\u91CC\u627E\u5230.\u4E0E301\u72B6\u6001\u7801\u6709\u76F8\u540C\u7684\u8BED\u4E49,\u4E14\u524D\u540E\u4E24\u6B21\u8BBF\u95EE\u5FC5\u987B\u4F7F\u7528\u76F8\u540C\u7684\u65B9\u6CD5(GETPOST).</p><ul><li>400 BadRequest(\u9519\u8BEF\u8BF7\u6C42) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u56E0\u53D1\u9001\u7684\u8BF7\u6C42\u8BED\u6CD5\u9519\u8BEF,\u670D\u52A1\u5668\u65E0\u6CD5\u6B63\u5E38\u8BFB\u53D6.</p><ul><li>401 Unauthorized(\u672A\u6388\u6743) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u9700\u8981\u8EAB\u4EFD\u9A8C\u8BC1\u540E\u624D\u80FD\u83B7\u53D6\u6240\u8BF7\u6C42\u7684\u5185\u5BB9,\u7C7B\u4F3C\u4E8E403\u9519\u8BEF.\u4E0D\u540C\u70B9\u662F.401\u9519\u8BEF\u540E,\u53EA\u8981\u6B63\u786E\u8F93\u5165\u5E10\u53F7\u5BC6\u7801,\u9A8C\u8BC1\u5373\u53EF\u901A\u8FC7.</p><ul><li>402 PaymentRequired(\u9700\u8981\u4ED8\u6B3E) (HTTP/0.9and1.1)</li></ul><p>\u8BE5\u72B6\u6001\u7801\u88AB\u4FDD\u7559\u4EE5\u4F9B\u5C06\u6765\u4F7F\u7528.\u521B\u5EFA\u6B64\u4EE3\u7801\u6700\u521D\u7684\u76EE\u7684\u662F\u4E3A\u6570\u5B57\u652F\u4ED8\u7CFB\u7EDF\u800C\u7528,\u7136\u800C,\u5230\u73B0\u5728\u4E5F\u6CA1\u6295\u5165\u4F7F\u7528.</p><ul><li>403 Forbidden(\u7981\u6B62\u8BBF\u95EE) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u5BA2\u6237\u7AEF\u6CA1\u6709\u6743\u5229\u8BBF\u95EE\u6240\u8BF7\u6C42\u5185\u5BB9,\u670D\u52A1\u5668\u62D2\u7EDD\u672C\u6B21\u8BF7\u6C42.</p><ul><li>404 NotFound(\u672A\u627E\u5230) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u670D\u52A1\u5668\u627E\u4E0D\u5230\u6240\u8BF7\u6C42\u7684\u8D44\u6E90.\u7531\u4E8E\u7ECF\u5E38\u53D1\u751F\u6B64\u79CD\u60C5\u51B5,\u6240\u4EE5\u8BE5\u72B6\u6001\u7801\u5728\u4E0A\u7F51\u65F6\u662F\u975E\u5E38\u5E38\u89C1\u7684.</p><ul><li>405 MethodNotAllowed(\u4E0D\u5141\u8BB8\u4F7F\u7528\u8BE5\u65B9\u6CD5) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u8BE5\u8BF7\u6C42\u4F7F\u7528\u7684\u65B9\u6CD5\u88AB\u670D\u52A1\u5668\u7AEF\u7981\u6B62\u4F7F\u7528,RFC2616\u4E2D\u89C4\u5B9A,GET\u548CHEAD\u65B9\u6CD5\u4E0D\u80FD\u88AB\u7981\u6B62.</p><ul><li>406 NotAcceptable(\u65E0\u6CD5\u63A5\u53D7) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u5728\u8FDB\u884C\u670D\u52A1\u5668\u9A71\u52A8\u5185\u5BB9\u534F\u5546\u540E,\u6CA1\u6709\u53D1\u73B0\u5408\u9002\u7684\u5185\u5BB9\u4F20\u56DE\u7ED9\u5BA2\u6237\u7AEF.</p><ul><li>407 ProxyAuthenticationRequired(\u8981\u6C42\u4EE3\u7406\u8EAB\u4EFD\u9A8C\u8BC1) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u7C7B\u4F3C\u4E8E\u72B6\u6001\u7801401,\u4E0D\u8FC7\u9700\u8981\u901A\u8FC7\u4EE3\u7406\u624D\u80FD\u8FDB\u884C\u9A8C\u8BC1.</p><ul><li>408 RequestTimeout(\u8BF7\u6C42\u8D85\u65F6) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u5BA2\u6237\u7AEF\u6CA1\u6709\u5728\u670D\u52A1\u5668\u9884\u5907\u7B49\u5F85\u7684\u65F6\u95F4\u5185\u5B8C\u6210\u4E00\u4E2A\u8BF7\u6C42\u7684\u53D1\u9001.\u8FD9\u610F\u5473\u7740\u670D\u52A1\u5668\u5C06\u4F1A\u5207\u65AD\u548C\u5BA2\u6237\u7AEF\u7684\u8FDE\u63A5.\u5728\u5176\u4ED6\u6D4F\u89C8\u5668\u4E2D,\u8FD9\u79CD\u54CD\u5E94\u66F4\u5E38\u89C1\u4E00\u4E9B,\u4F8B\u5982Chrome\u548CIE9,\u76EE\u7684\u662F\u4E3A\u4E86\u4F7F\u7528HTTP\u9884\u8FDE\u673A\u5236\u52A0\u5FEB\u6D4F\u89C8\u901F\u5EA6.\u540C\u65F6\u6CE8\u610F,\u4E00\u4E9B\u670D\u52A1\u5668\u4E0D\u53D1\u9001\u6B64\u79CD\u54CD\u5E94\u5C31\u76F4\u63A5\u5207\u65AD\u8FDE\u63A5.</p><ul><li>409 Conflict(\u51B2\u7A81) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u8BE5\u8BF7\u6C42\u4E0E\u670D\u52A1\u5668\u7684\u5F53\u524D\u72B6\u6001\u6240\u51B2\u7A81.</p><ul><li>410 Gone(\u5DF2\u5931\u6548) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u6240\u8BF7\u6C42\u7684\u8D44\u6E90\u5DF2\u7ECF\u88AB\u5220\u9664.</p><ul><li>411 LengthRequired(\u9700\u8981\u5185\u5BB9\u957F\u5EA6\u5934) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u56E0\u670D\u52A1\u5668\u5728\u672C\u6B21\u8BF7\u6C42\u4E2D\u9700\u8981Content-Length\u5934\u5B57\u6BB5,\u800C\u5BA2\u6237\u7AEF\u6CA1\u6709\u53D1\u9001.\u6240\u4EE5,\u670D\u52A1\u5668\u62D2\u7EDD\u4E86\u8BE5\u8BF7\u6C42.</p><ul><li>412 PreconditionFailed(\u9884\u5904\u7406\u5931\u8D25) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u670D\u52A1\u5668\u6CA1\u80FD\u6EE1\u8DB3\u5BA2\u6237\u7AEF\u5728\u83B7\u53D6\u8D44\u6E90\u65F6\u5728\u8BF7\u6C42\u5934\u5B57\u6BB5\u4E2D\u8BBE\u7F6E\u7684\u5148\u51B3\u6761\u4EF6.</p><ul><li>413 RequestEntityTooLarge(\u8BF7\u6C42\u5B9E\u4F53\u8FC7\u957F) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u8BF7\u6C42\u5B9E\u4F53\u5927\u5C0F\u8D85\u8FC7\u670D\u52A1\u5668\u7684\u8BBE\u7F6E\u7684\u6700\u5927\u9650\u5236,\u670D\u52A1\u5668\u53EF\u80FD\u4F1A\u5173\u95EDHTTP\u94FE\u63A5\u5E76\u8FD4\u56DERetry-After\u5934\u5B57\u6BB5.</p><ul><li>414 Request-URITooLong(\u8BF7\u6C42\u7F51\u5740\u8FC7\u957F) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u5BA2\u6237\u7AEF\u8BF7\u6C42\u6240\u5305\u542B\u7684URI\u5730\u5740\u592A\u957F,\u4EE5\u81F3\u4E8E\u670D\u52A1\u5668\u65E0\u6CD5\u5904\u7406.</p><ul><li>415 UnsupportedMediaType(\u5A92\u4F53\u7C7B\u578B\u4E0D\u652F\u6301) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u670D\u52A1\u5668\u4E0D\u652F\u6301\u5BA2\u6237\u7AEF\u6240\u8BF7\u6C42\u7684\u5A92\u4F53\u7C7B\u578B,\u56E0\u6B64\u62D2\u7EDD\u8BE5\u8BF7\u6C42.</p><ul><li>416 RequestedRangeNotSatisfiable(\u8BF7\u6C42\u8303\u56F4\u4E0D\u5408\u8981\u6C42) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u8BF7\u6C42\u4E2D\u5305\u542B\u7684Range\u5934\u5B57\u6BB5\u65E0\u6CD5\u88AB\u6EE1\u8DB3,\u901A\u5E38\u662F\u56E0\u4E3ARange\u4E2D\u7684\u6570\u5B57\u8303\u56F4\u8D85\u51FA\u6240\u8BF7\u6C42\u8D44\u6E90\u7684\u5927\u5C0F.</p><ul><li>417 ExpectationFailed(\u9884\u671F\u7ED3\u679C\u5931\u8D25) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u5728\u8BF7\u6C42\u5934Expect\u4E2D\u6307\u5B9A\u7684\u9884\u671F\u5185\u5BB9\u65E0\u6CD5\u88AB\u670D\u52A1\u5668\u6EE1\u8DB3.</p><ul><li>500 InternalServerError(\u5185\u90E8\u670D\u52A1\u5668\u9519\u8BEF) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u670D\u52A1\u5668\u9047\u5230\u672A\u77E5\u7684\u65E0\u6CD5\u89E3\u51B3\u7684\u95EE\u9898.</p><ul><li>501 NotImplemented(\u672A\u5B9E\u73B0) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u670D\u52A1\u5668\u4E0D\u652F\u6301\u8BE5\u8BF7\u6C42\u4E2D\u4F7F\u7528\u7684\u65B9\u6CD5,\u6BD4\u5982POST\u548CPUT.\u53EA\u6709GET\u548CHEAD\u662FRFC2616\u89C4\u8303\u4E2D\u89C4\u5B9A\u670D\u52A1\u5668\u5FC5\u987B\u5B9E\u73B0\u7684\u65B9\u6CD5.</p><ul><li>502 BadGateway(\u7F51\u5173\u9519\u8BEF) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u670D\u52A1\u5668\u4F5C\u4E3A\u7F51\u5173\u4E14\u4ECE\u4E0A\u6E38\u670D\u52A1\u5668\u83B7\u53D6\u5230\u4E86\u4E00\u4E2A\u65E0\u6548\u7684HTTP\u54CD\u5E94.</p><ul><li>503 ServiceUnavailable(\u670D\u52A1\u4E0D\u53EF\u7528) (HTTP/0.9\u53EF\u7528)</li></ul><p>\u7531\u4E8E\u4E34\u65F6\u7684\u670D\u52A1\u5668\u7EF4\u62A4\u6216\u8005\u8FC7\u8F7D,\u670D\u52A1\u5668\u5F53\u524D\u65E0\u6CD5\u5904\u7406\u8BF7\u6C42.\u8FD9\u4E2A\u72B6\u51B5\u662F\u4E34\u65F6\u7684,\u5E76\u4E14\u5C06\u5728\u4E00\u6BB5\u65F6\u95F4\u4EE5\u540E\u6062\u590D.\u5982\u679C\u80FD\u591F\u9884\u8BA1\u5EF6\u8FDF\u65F6\u95F4,\u90A3\u4E48\u54CD\u5E94\u4E2D\u53EF\u4EE5\u5305\u542B\u4E00\u4E2ARetry-After:\u5934\u7528\u4EE5\u6807\u660E\u8FD9\u4E2A\u5EF6\u8FDF\u65F6\u95F4.\u5982\u679C\u6CA1\u6709\u7ED9\u51FA\u8FD9\u4E2ARetry-After:\u4FE1\u606F\uFF0C\u90A3\u4E48\u5BA2\u6237\u7AEF\u5E94\u5F53\u4EE5\u5904\u7406500\u54CD\u5E94\u7684\u65B9\u5F0F\u5904\u7406\u5B83.\u540C\u65F6,\u8FD9\u79CD\u60C5\u51B5\u4E0B,\u4E00\u4E2A\u53CB\u597D\u7684\u7528\u4E8E\u89E3\u91CA\u670D\u52A1\u5668\u51FA\u73B0\u95EE\u9898\u7684\u9875\u9762\u5E94\u5F53\u88AB\u8FD4\u56DE,\u5E76\u4E14,\u7F13\u5B58\u76F8\u5173\u7684HTTP\u5934\u4FE1\u606F\u4E5F\u5E94\u8BE5\u5305\u542B,\u56E0\u4E3A\u901A\u5E38\u8FD9\u79CD\u9519\u8BEF\u63D0\u793A\u7F51\u9875\u4E0D\u5E94\u5F53\u88AB\u5BA2\u6237\u7AEF\u7F13\u5B58.</p><ul><li>504 GatewayTimeout(\u7F51\u5173\u8D85\u65F6) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u670D\u52A1\u5668\u4F5C\u4E3A\u7F51\u5173\u4E14\u4E0D\u80FD\u4ECE\u4E0A\u6E38\u670D\u52A1\u5668\u53CA\u65F6\u7684\u5F97\u5230\u54CD\u5E94\u8FD4\u56DE\u7ED9\u5BA2\u6237\u7AEF.</p><ul><li>505 HTTPVersionNotSupported(HTTP\u7248\u672C\u4E0D\u53D7\u652F\u6301) (HTTP/1.1\u53EF\u7528)</li></ul><p>\u670D\u52A1\u5668\u4E0D\u652F\u6301\u5BA2\u6237\u7AEF\u53D1\u9001\u7684HTTP\u8BF7\u6C42\u4E2D\u6240\u4F7F\u7528\u7684HTTP\u534F\u8BAE\u7248\u672C.</p>',86),p=[u];function n(r,a){return t(),e("div",null,p)}var P=l(T,[["render",n],["__file","HTTP-01.html.vue"]]);export{P as default};
